class AssociativeMemory:
    def __init__(self, dim, alpha=1.0, eta=0.01):
        self.dim = dim
        self.alpha = alpha
        self.eta = eta
        self.M = [[0.0] * dim for _ in range(dim)]
        self.key_history = []
        self.target_history = []
        self.beta = 0.9
        self.momentum = [[0.0] * dim for _ in range(dim)]
        self.query_count = 0
        self.activation_cache = {}
        self.decay = 0.999

    def _matvec(self, M, v):
        out = [0.0] * self.dim
        for i in range(self.dim):
            s = 0.0
            row = M[i]
            for j in range(self.dim):
                s += row[j] * v[j]
            out[i] = s
        return out

    def _similarity(self, a, b):
        dot = sum(ai * bi for ai, bi in zip(a, b))
        norm_a = sum(ai * ai for ai in a) ** 0.5
        norm_b = sum(bi * bi for bi in b) ** 0.5
        if norm_a == 0 or norm_b == 0:
            return 0.0
        return dot / (norm_a * norm_b)

    def query(self, key):
        self.query_count += 1
        key_tuple = tuple(key)
        if key_tuple in self.activation_cache:
            return list(self.activation_cache[key_tuple])

        base_activation = self._matvec(self.M, key)
        if self.key_history:
            similarities = [self._similarity(key, k) for k in self.key_history]
            max_sim = max(similarities) if similarities else 0
            if max_sim > 0.7:
                idx = similarities.index(max_sim)
                target_influence = self.target_history[idx]
                blend = max_sim * self.alpha
                activation = [
                    (1 - blend) * ba + blend * ti
                    for ba, ti in zip(base_activation, target_influence)
                ]
            else:
                activation = base_activation
        else:
            activation = base_activation

        activation = [a * (1.0 + 0.1 * self.alpha * (k - 0.5))
                      for a, k in zip(activation, key)]
        self.activation_cache[key_tuple] = tuple(activation)
        if len(self.activation_cache) > 100:
            self.activation_cache.pop(next(iter(self.activation_cache)))
        return activation

    def update(self, key, target):
        act = self.query(key)
        error = [t - a for t, a in zip(target, act)]
        norm_error = sum(e * e for e in error) ** 0.5
        if norm_error > 0:
            error = [e / norm_error for e in error]

        for i in range(self.dim):
            for j in range(self.dim):
                grad = error[i] * key[j] - 0.001 * self.M[i][j]
                self.momentum[i][j] = self.beta * self.momentum[i][j] + self.eta * grad
                self.M[i][j] += self.momentum[i][j]

        self.key_history.append(key[:])
        self.target_history.append(target[:])
        if len(self.key_history) > 50:
            self.key_history.pop(0)
            self.target_history.pop(0)

        self.eta *= self.decay

